css_snippet:
/* Reference font for body text, establishing a baseline x-height */
body {
  font-family: "Inter", sans-serif;
  font-size: 16px;
}

/* Headline font with a naturally smaller x-height relative to its cap-height */
h1 {
  font-family: "Playfair Display", serif;
  font-size: 2.8em;
  /* Apply font-size-adjust to 'Playfair Display' to visually match 'Inter's x-height.
     A value of 0.5 is a common x-height ratio for many sans-serif fonts.
     This scales the font so its x-height equals 0.5 times its computed font-size. */
  font-size-adjust: 0.5; 
}

/* Another UI element font, potentially needing different adjustment */
.caption-text {
  font-family: "Roboto Mono", monospace;
  font-size: 0.9em;
  /* Monospace fonts often have larger x-heights, adjust for visual harmony */
  font-size-adjust: 0.55; /* Slightly increase its x-height relative to its default */
}
